/** 根据 id 查武器 */
export const weaponById = (id) => weapons.find((w) => w.id === id);
/** 取武器某形态名(无则退化到 base) */
export const nameAtTier = (w, tier) => {
    return w[tier] ?? w.base;
};
/** 取武器在指定形态的 4 项数值(baseStats * TIER_MULTIPLIER) */
export const statsAtTier = (w, tier) => {
    const m = TIER_MULTIPLIER[tier];
    return {
        atk: Math.round(w.baseStats.atk * m),
        def: Math.round(w.baseStats.def * m),
        spd: Math.round(w.baseStats.spd * m),
        crit: Math.round(w.baseStats.crit * m),
    };
};
/** 武器武器的"下一形态"(artifact 时返回 null) */
export const nextTier = (tier) => {
    const i = WEAPON_TIERS.indexOf(tier);
    if (i < 0 || i >= WEAPON_TIERS.length - 1)
        return null;
    return WEAPON_TIERS[i + 1];
};
