<script setup lang="ts">
/**
 * 武器图标组件(最终版)
 *
 * 渲染策略:
 *  - 用 WeaponArt 渲染 25 把自绘 SVG(64x64 几何 silhouette)
 *  - 外层 tier 框 + 觉醒角标由本组件负责
 *
 * 后续要换真美术:把 WeaponArt 内的 ART[id] 改为 "/assets/icons/xxx.svg",
 * 本组件再分支 isAsset 即可,接口不变
 */
import { computed } from 'vue'
import type { Weapon, WeaponTier, AwakenType } from '@/data/weapons'
import { TIER_META } from '@/data/weapons'
import WeaponArt from './WeaponArt.vue'

const props = withDefaults(
  defineProps<{
    weapon: Weapon
    tier?: WeaponTier
    size?: number
    showAwakenBadge?: boolean
  }>(),
  { tier: 'base', size: 64, showAwakenBadge: true },
)

const meta = computed(() => TIER_META[props.tier])

const awakenStyle = (t: AwakenType) =>
  t === 1 ? 'bg-sky-600 text-white' : 'bg-purple-600 text-white'
</script>

<template>
  <div
    class="relative inline-flex items-center justify-center rounded-lg overflow-hidden ring-1"
    :class="meta.border"
    :style="{ width: size + 'px', height: size + 'px' }"
  >
    <div class="absolute inset-0" :class="meta.bg" />
    <WeaponArt :id="weapon.id" :size="Math.round(size * 0.78)" />

    <span
      v-if="showAwakenBadge"
      class="absolute bottom-0 right-0 px-1 text-[9px] font-bold rounded-tl"
      :class="awakenStyle(weapon.awakenType)"
    >
      觉{{ weapon.awakenType }}
    </span>
  </div>
</template>
